SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;
-- operation_history DDL
DROP TABLE IF EXISTS `operation_history`;
CREATE TABLE `operation_history` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "主键",
`project_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NONE' Comment "项目id",
`create_time` DATETIME NOT NULL Comment "操作时间",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "操作人",
`source_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "资源id",
`type` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "操作类型/add/update/delete",
`module` VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
`ref_id` BIGINT NULL Comment "关联id（关联变更记录id来源）",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_module`(`module` ASC) USING BTREE,
INDEX `idx_project_id`(`project_id` ASC) USING BTREE,
INDEX `idx_source_id`(`source_id` ASC) USING BTREE,
INDEX `idx_type`(`type` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 1 ROW_FORMAT = Dynamic COMMENT = "变更记录";
-- operation_log DDL
DROP TABLE IF EXISTS `operation_log`;
CREATE TABLE `operation_log` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "主键",
`project_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NONE' Comment "项目id",
`organization_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NONE' Comment "组织id",
`create_time` DATETIME NOT NULL Comment "操作时间",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "操作人",
`source_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "资源id",
`method` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "操作方法",
`type` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "操作类型/add/update/delete",
`module` VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
`content` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "操作详情",
`path` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "操作路径",
`original_value` LONGBLOB NULL Comment "变更前内容",
`modified_value` LONGBLOB NULL Comment "变更后内容",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_method`(`method` ASC) USING BTREE,
INDEX `idx_module`(`module` ASC) USING BTREE,
INDEX `idx_organization_id`(`organization_id` ASC) USING BTREE,
INDEX `idx_project_id`(`project_id` ASC) USING BTREE,
INDEX `idx_source_id`(`source_id` ASC) USING BTREE,
INDEX `idx_type`(`type` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 1 ROW_FORMAT = Dynamic COMMENT = "操作日志";
-- organization DDL
DROP TABLE IF EXISTS `organization`;
CREATE TABLE `organization` (`id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组织ID",
`num` BIGINT NOT NULL AUTO_INCREMENT Comment "组织编号",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组织名称",
`description` VARCHAR(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "描述",
`create_time` DATETIME NULL Comment "创建时间",
`update_time` DATETIME NULL ON UPDATE CURRENT_TIMESTAMP(0) Comment "更新时间",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "创建人",
`update_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "修改人",
`deleted` BIT NOT NULL DEFAULT b'0' Comment "是否删除",
`delete_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "删除人",
`delete_time` DATETIME NULL Comment "删除时间",
`enable` BIT NOT NULL DEFAULT b'1' Comment "是否启用",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_deleted`(`deleted` ASC) USING BTREE,
INDEX `idx_name`(`name` ASC) USING BTREE,
UNIQUE INDEX `idx_num`(`num` ASC) USING BTREE,
INDEX `idx_update_time`(`update_time` DESC) USING BTREE,
INDEX `idx_update_user`(`update_user` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 1 ROW_FORMAT = Dynamic COMMENT = "组织";
-- project DDL
DROP TABLE IF EXISTS `project`;
CREATE TABLE `project` (`id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "项目ID",
`num` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "项目编号",
`organization_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组织ID",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "项目名称",
`description` VARCHAR(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "项目描述",
`create_time` DATETIME NOT NULL Comment "创建时间",
`update_time` DATETIME NOT NULL Comment "更新时间",
`update_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "修改人",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "创建人",
`delete_time` DATETIME NULL Comment "删除时间",
`deleted` BIT NOT NULL DEFAULT b'0' Comment "是否删除",
`delete_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "删除人",
`enable` BIT NOT NULL DEFAULT b'1' Comment "是否启用",
`module_setting` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "模块设置",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_deleted`(`deleted` ASC) USING BTREE,
INDEX `idx_name`(`name` ASC) USING BTREE,
UNIQUE INDEX `idx_num`(`num` ASC) USING BTREE,
INDEX `idx_organization_id`(`organization_id` ASC) USING BTREE,
INDEX `idx_update_time`(`update_time` DESC) USING BTREE,
INDEX `idx_update_user`(`update_user` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "项目";
-- system_user DDL
DROP TABLE IF EXISTS `system_user`;
CREATE TABLE `system_user` (`id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户ID",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户名",
`email` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户邮箱",
`password` VARCHAR(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL Comment "用户密码",
`enable` BIT NOT NULL DEFAULT b'1' Comment "是否启用",
`create_time` DATETIME NOT NULL Comment "创建时间",
`update_time` DATETIME NOT NULL Comment "更新时间",
`language` VARCHAR(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "语言",
`last_organization_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "当前组织ID",
`phone` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "手机号",
`last_project_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "当前项目ID",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "创建人",
`update_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "修改人",
`deleted` BIT NOT NULL DEFAULT b'0' Comment "是否删除",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_deleted`(`deleted` ASC) USING BTREE,
UNIQUE INDEX `idx_email`(`email` ASC) USING BTREE,
INDEX `idx_name`(`name` ASC) USING BTREE,
INDEX `idx_organization_id`(`last_organization_id` ASC) USING BTREE,
INDEX `idx_project_id`(`last_project_id` ASC) USING BTREE,
INDEX `idx_update_time`(`update_time` DESC) USING BTREE,
INDEX `idx_update_user`(`update_user` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "用户";
-- user_role DDL
DROP TABLE IF EXISTS `user_role`;
CREATE TABLE `user_role` (`id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组ID",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组名称",
`description` VARCHAR(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "描述",
`internal` BIT NOT NULL Comment "是否是内置用户组",
`type` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "所属类型 SYSTEM ORGANIZATION PROJECT",
`create_time` DATETIME NOT NULL Comment "创建时间",
`update_time` DATETIME NOT NULL Comment "更新时间",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "创建人(操作人）",
`scope_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "应用范围",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_create_user`(`create_user` ASC) USING BTREE,
INDEX `idx_group_name`(`name` ASC) USING BTREE,
INDEX `idx_scope_id`(`scope_id` ASC) USING BTREE,
INDEX `idx_update_time`(`update_time` DESC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "用户组";
-- user_role_permission DDL
DROP TABLE IF EXISTS `user_role_permission`;
CREATE TABLE `user_role_permission` (`id` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
`role_id` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户组ID",
`permission_id` VARCHAR(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "权限ID",
INDEX `idx_group_id`(`role_id` ASC) USING BTREE,
INDEX `idx_permission_id`(`permission_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "用户组权限";
-- user_role_relation DDL
DROP TABLE IF EXISTS `user_role_relation`;
CREATE TABLE `user_role_relation` (`id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户组关系ID",
`user_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "用户ID",
`role_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组ID",
`source_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "组织或项目ID",
`organization_id` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "记录所在的组织ID",
`create_time` DATETIME NOT NULL Comment "创建时间",
`create_user` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "创建人",
INDEX `idx_create_time`(`create_time` DESC) USING BTREE,
INDEX `idx_group_id`(`role_id` ASC) USING BTREE,
INDEX `idx_source_id`(`source_id` ASC) USING BTREE,
INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "用户组关系";
